import React from 'react';
import {
  Card,
  Stack,
  Heading,
  Text,
  Divider,
  Box
} from '@ggui-ai/design/primitives';

interface Props {
  /** City name */
  city: string;
  /** Current temperature */
  temperature: number;
  /** Weather condition (Sunny, Cloudy, Rainy, etc.) */
  condition: string;
  /** Humidity percentage */
  humidity: number;
  /** Wind speed */
  windSpeed: number;
  /** Temperature unit (C or F) */
  unit?: string;
  /** 5-day forecast array */
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>;
}

/**
 * WeatherCard Component
 * 
 * A visually engaging weather display card with current conditions and a 5-day forecast.
 * Uses design system tokens for consistent styling and layout.
 */
const WeatherCard: React.FC<Props> = ({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast
}) => {
  // Helper to resolve a weather emoji based on condition string if specific icon isn't provided
  const getConditionEmoji = (cond: string) => {
    const c = (cond || '').toLowerCase();
    if (c.includes('sunny') || c.includes('clear')) return '☀️';
    if (c.includes('cloudy') || c.includes('overcast')) return '☁️';
    if (c.includes('rain') || c.includes('drizzle')) return '🌧️';
    if (c.includes('snow')) return '❄️';
    if (c.includes('thunder') || c.includes('storm')) return '⛈️';
    if (c.includes('fog') || c.includes('mist')) return '🌫️';
    return '⛅';
  };

  if (!forecast || forecast.length === 0) {
    return null;
  }

  return (
    <Card
      shadow="md"
      radius="xl"
      padding="var(--ggui-spacing-6)"
      style={{
        backgroundColor: 'var(--ggui-color-surface)',
        borderColor: 'var(--ggui-color-outlineVariant)',
        width: '100%',
        maxWidth: 'var(--ggui-spacing-80)'
      }}
    >
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack direction="row" justify="space-between" align="center">
          <Heading level={3} color="var(--ggui-color-onSurface)">
            {city}
          </Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            {condition}
          </Text>
        </Stack>

        {/* Hero Section */}
        <Stack align="center" gap="var(--ggui-spacing-4)">
          <Box style={{
            padding: 'var(--ggui-spacing-4)',
            backgroundColor: 'var(--ggui-color-primaryContainer)',
            borderRadius: 'var(--ggui-spacing-4)',
            textAlign: 'center'
          }}>
            <Stack direction="row" align="center" gap="var(--ggui-spacing-1)">
              <Heading level={1} color="var(--ggui-color-onPrimaryContainer)">
                {temperature}
              </Heading>
              <Text
                variant="body"
                color="var(--ggui-color-onPrimaryContainer)"
                style={{ fontSize: 'var(--ggui-font-size-xl)', fontWeight: 'bold' }}
              >
                °{unit}
              </Text>
            </Stack>
          </Box>
          <Text
            variant="body"
            aria-hidden="true"
            style={{ 
              fontSize: 'var(--ggui-font-size-3xl)', 
              lineHeight: 'var(--ggui-spacing-12)' 
            }}
          >
            {getConditionEmoji(condition)}
          </Text>
        </Stack>

        {/* Metrics Row */}
        <Stack direction="row" justify="space-around" align="center">
          <Stack align="center" gap="var(--ggui-spacing-1)">
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant)"
              style={{ fontWeight: '500' }}
            >
              Humidity
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurface)" style={{ fontWeight: 'bold' }}>
              {humidity}%
            </Text>
          </Stack>

          <Box style={{ 
            width: 'var(--ggui-spacing-px)', 
            height: 'var(--ggui-spacing-8)', 
            backgroundColor: 'var(--ggui-color-outlineVariant)' 
          }} />

          <Stack align="center" gap="var(--ggui-spacing-1)">
            <Text
              variant="caption"
              color="var(--ggui-color-onSurfaceVariant)"
              style={{ fontWeight: '500' }}
            >
              Wind Speed
            </Text>
            <Text variant="body" color="var(--ggui-color-onSurface)" style={{ fontWeight: 'bold' }}>
              {windSpeed} km/h
            </Text>
          </Stack>
        </Stack>

        <Divider />

        {/* Forecast Strip */}
        <Stack direction="row" justify="space-between" align="center" gap="var(--ggui-spacing-3)">
          {forecast.slice(0, 5).map((item, index) => (
            <Stack key={index} align="center" gap="var(--ggui-spacing-1)">
              <Text
                variant="caption"
                color="var(--ggui-color-onSurfaceVariant)"
                style={{ fontWeight: '500' }}
              >
                {item.day || '---'}
              </Text>
              <Text variant="body" style={{ fontSize: 'var(--ggui-font-size-xl)' }} aria-hidden="true">
                {item.icon || '☁️'}
              </Text>
              <Stack direction="row" gap="var(--ggui-spacing-1)" align="center">
                <Text
                  variant="caption"
                  color="var(--ggui-color-primary)"
                >
                  {item.high ?? 0}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-outline)">
                  {item.low ?? 0}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
};

export default WeatherCard;
